// Package hardwarehealth was generated by IDLC from HardwareHealth.idl.
// It is part of module fitness.
// The remaining comment is for module fitness.
package hardwarehealth

import (
	"context"
	"time"

	"github.com/arminguenther/xeruspower-go/v40412/idl"
	"github.com/arminguenther/xeruspower-go/v40412/idl/event"
)

// hardware failure types
const (
	FAILURE_TYPE_NETWORK_DEVICE_NOT_DETECTED     int32 = 1
	FAILURE_TYPE_I2C_BUS_STUCK                   int32 = 2
	FAILURE_TYPE_SUB_CTRL_NOT_REACHABLE          int32 = 3
	FAILURE_TYPE_SUB_CTRL_MALFUNCTION            int32 = 4
	FAILURE_TYPE_OUTLET_POWER_STATE_INCONSISTENT int32 = 5
	FAILURE_TYPE_SUB_CTRL_INCOMPATIBLE           int32 = 6
)

type HardwareHealth interface {
	idl.Object

	// Return a vector with past and present hardware failures.
	//
	//	@return hardware failure vector
	GetFailures(ctx context.Context) ([]Failure, error)
}

// Hardware Failure
type Failure struct {
	CreationOrderId       int32     // failures created later have a larger id; range 1..failure-count
	ComponentId           string    // the ID of the affected hardware component
	Type                  int32     // one of the hardware failure type constants
	Description           string    // human-readable string describing HW component and failure
	IsAsserted            bool      // true when the failure is currently asserted
	LastAssertTimeStamp   time.Time // UNIX timestamp (UTC) when the failure was last asserted
	LastDeassertTimeStamp time.Time // UNIX timestamp (UTC) when the failure was last deasserted (0 if asserted)
	AssertCount           int32     // count of assertions
}

// Event that is sent when the hardware failure status changes
type FailureStatusChangedEvent interface {
	event.Event
	ComponentId() string // the ID of the affected hardware component
	FailureType() int32  // one of the hardware failure type constants
	IsAsserted() bool    // true when the failure is currently asserted
	isFailureStatusChangedEvent()
}
